#!/usr/bin/perl
use strict;
use warnings;
use CAM::PDF;

# Path to the PDF file
my $pdf_file = 'path/to/your/pdffile.pdf';

# Open the PDF
my $pdf = CAM::PDF->new($pdf_file);

# Function to extract metadata
sub extract_metadata {
    my $pdf = shift;
    my ($info) = $pdf->getInfo();
    return $info;
}

# Function to extract text from a specific page
sub extract_text_from_page {
    my ($pdf, $page_number) = @_;
    my $page = $pdf->getPageText($page_number - 1);
    return $page;
}

# Function to extract tables from a specific page
sub extract_tables_from_page {
    my ($pdf, $page_number) = @_;
    my $page = $pdf->getPageText($page_number - 1);
    # Simple table extraction logic (can be enhanced)
    my @lines = split /\n/, $page;
    my @tables;
    for my $line (@lines) {
        if ($line =~ /\|/) {
            push @tables, $line;
        }
    }
    return @tables;
}

